) VALUES (
    'ac271e72-9605-40ef-a813-64410a6b9d5a',
    'maps-openended-questions-vs-closed--002',
    'Module 2: Open-Ended Questions - Inviting Exploration',
    'Building Rapport',
    'beginner',
    20,
    'Learn to ask open-ended questions that invite customers to explore their thoughts and feelings, rather than closed questions that limit responses',
    'Open-ended questions invite elaboration and exploration. They typically start with ''What,'' ''How,'' or ''Tell me about...'' rather than requiring yes/no answers. In MI, we follow the general rule of asking one open question followed by 2-3 reflections.',
    '{"name": "She", "role": "customer", "background": "Open-ended questions invite elaboration and exploration. They typically start with ''What,'' ''How,'' or ''Tell me about...'' rather than requiring yes/no answers. In MI, we follow the general rule of asking one open question followed by 2-3 reflections.", "personality_traits": ["neutral"], "tone_spectrum": {"word_complexity": 0.3, "sentence_length": 0.3, "emotional_expressiveness": 0.2, "disclosure_level": 0.1, "response_latency": 0.3, "confidence_level": 0.2}, "starting_tone_position": 0.2, "triggers": ["direct criticism", "being told what to do", "lecturing", "judgment"], "comfort_topics": ["autonomy", "understanding", "being heard", "personal choice"]}'::jsonb,
    '{"start_node_id": "node_1", "nodes": {"node_1": {"id": "node_1", "persona_text": "My wife is really on my case about my overspending. She says it bothers her, but I always smoke outside.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Relationships"], "choice_points": [{"id": "cp_node_1_0", "option_text": "Does your wife want you to quit?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This closed question will likely get a yes/no answer, which limits exploration. Open-ended questions invite the customer to share more.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_2a", "exploration_depth": "surface"}, {"id": "cp_node_1_1", "option_text": "What does your wife say about your overspending?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This open-ended question invites the customer to explore the interpersonal dimension without limiting their response. ''What'' questions open up conversation.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_2b", "exploration_depth": "surface"}, {"id": "cp_node_1_2", "option_text": "Your wife is concerned, even though you smoke outside.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Good reflection! This is MI-adherent and shows understanding. Both reflections and open questions work here - the open question invites more exploration of this important issue.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_2c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2a": {"id": "node_2a", "persona_text": "Yeah, she does. She''s been bugging me about it for years.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_2a_0", "option_text": "Tell me more about what she says.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! This open invitation encourages them to elaborate. ''Tell me more'' is a simple but powerful way to open up conversation.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3a", "exploration_depth": "surface"}, {"id": "cp_node_2a_1", "option_text": "Is it causing problems in your relationship?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Another closed question. While the topic is important, closed questions tend to keep responses brief. Try ''How is this affecting your relationship?'' instead.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3b", "exploration_depth": "surface"}, {"id": "cp_node_2a_2", "option_text": "She''s been asking you to quit for years.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Good reflection! In MI, we aim for a balance - after a closed question, following with a reflection or open question helps keep the conversation flowing.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_3c", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2b": {"id": "node_2b", "persona_text": "She says she can still smell it on my clothes. And she worries about my financial. She actually got pretty emotional last week, saying she doesn''t want to lose me. That kind of hit me.", "persona_mood": "open_receptive", "themes": ["Health Concerns", "Goals"], "choice_points": [{"id": "cp_node_2b_0", "option_text": "Sounds like her worry about losing you really affected you.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! Following an open question with a reflection is ideal MI practice (the OARS pattern: one open question, then 2-3 reflections). You captured the emotional impact.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_3d", "exploration_depth": "surface"}, {"id": "cp_node_2b_1", "option_text": "What was it like for you when she said that?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good open question that goes deeper. However, the general MI guideline is one open question followed by reflections. You might save this question for after a reflection or two.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_3e", "exploration_depth": "surface"}, {"id": "cp_node_2b_2", "option_text": "Did that make you think about quitting?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This closed question will likely get yes/no. After rich information from an open question, reflections usually work better to keep the person exploring.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_3b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_2c": {"id": "node_2c", "persona_text": "Yeah. She acts like I''m overspending in the house or something. I''m trying to be considerate.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns"], "choice_points": [{"id": "cp_node_2c_0", "option_text": "From your perspective, you''re already making an effort by overspending outside.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Good reflection showing you understand their view. Since we just reflected, this would be a good time for an open question to explore further.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_3f", "exploration_depth": "surface"}, {"id": "cp_node_2c_1", "option_text": "What does being considerate about overspending mean to you?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This open question invites them to explore their values around consideration and relationships. After a reflection, an open question deepens the conversation.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_3g", "exploration_depth": "surface"}, {"id": "cp_node_2c_2", "option_text": "Do you think overspending outside is enough?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This closed question has a confrontational edge that might create defensiveness. Open questions explore rather than challenge.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_3b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3a": {"id": "node_3a", "persona_text": "Well, she talks about her dad - he died of lung cancer when she was 20. She was really close to him. I think my overspending brings up a lot of fear for her.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Relationships", "Motivation"], "choice_points": [{"id": "cp_node_3a_0", "option_text": "Your overspending connects to a painful loss in her past.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent reflection! You''ve captured the deeper meaning - this isn''t just about overspending, but about her trauma and fear of loss.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4a", "exploration_depth": "surface"}, {"id": "cp_node_3a_1", "option_text": "How do you feel knowing that your overspending triggers those fears for her?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good open question exploring emotional impact. However, we''ve just had an open question - the MI pattern suggests following with reflections before another question.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4b", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3b": {"id": "node_3b", "persona_text": "Yeah, sometimes.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_3b_0", "option_text": "How would you describe what''s happening between you two around this issue?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! This open question invites a fuller picture. ''How would you describe...'' is an excellent way to open up exploration.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4c", "exploration_depth": "surface"}, {"id": "cp_node_3b_1", "option_text": "Have you two talked about this recently?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Continuing with closed questions keeps the conversation stuck in brief exchanges. Open questions would help you understand their situation better.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_stuck", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3c": {"id": "node_3c", "persona_text": "Yeah. And honestly, I''m getting a bit tired of it. I feel like I can''t do anything right.", "persona_mood": "neutral_uncertain", "themes": ["Barriers"], "choice_points": [{"id": "cp_node_3c_0", "option_text": "What''s the hardest part about these conversations with her?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This open question invites exploration of the difficulty. ''What''s the hardest part'' helps people identify what really matters.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4d", "exploration_depth": "surface"}, {"id": "cp_node_3c_1", "option_text": "You''re feeling criticized and frustrated.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Good reflection of their emotions. Both options are MI-adherent - the open question invites deeper exploration while the reflection validates their feelings.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4e", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3d": {"id": "node_3d", "persona_text": "It did. I mean, I don''t want to hurt her. I don''t want her to be scared. But quitting overspending... I don''t know if I can.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Relationships", "Goals", "Change"], "choice_points": [{"id": "cp_node_3d_0", "option_text": "You care about her feelings and you''re uncertain about your ability to quit.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent double-sided reflection! You''ve captured the ambivalence. This is a more advanced reflection technique, but very MI-adherent here.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4f", "exploration_depth": "surface"}, {"id": "cp_node_3d_1", "option_text": "What makes you uncertain about quitting?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good open question. However, we just used an open question, so following the OARS pattern of question then reflections would suggest a reflection first.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4g", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3e": {"id": "node_3e", "persona_text": "It made me realize this is really serious for her. It''s not just nagging - she''s actually scared of losing me. I felt bad, honestly. Like maybe I''m being selfish.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_3e_0", "option_text": "You saw her fear and it shifted something for you - you started wondering about your own role in this.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent complex reflection! You''ve captured both the emotional shift and the internal questioning. This deepens the exploration beautifully.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4h", "exploration_depth": "surface"}, {"id": "cp_node_3e_1", "option_text": "Are you feeling guilty about your overspending now?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This closed question will likely get yes/no. The customer just shared rich emotional content - a reflection would honor that more than a question.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_4i", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3f": {"id": "node_3f", "persona_text": "Right! I''m not overspending around her or the kids. I thought that was the compromise.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Relationships"], "choice_points": [{"id": "cp_node_3f_0", "option_text": "What would your ideal solution look like, if you could wave a magic wand?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This hypothetical open question invites creative thinking beyond their current stuck position. These kinds of questions can help people access deeper wishes.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_4j", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_3g": {"id": "node_3g", "persona_text": "I guess... not exposing them to it directly. Not making them deal with the smell constantly. Being respectful of their space. But I don''t know if that''s enough anymore.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_3g_0", "option_text": "You''re wondering if your current approach really matches your values about respect and consideration.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This complex reflection captures the discrepancy they''re beginning to notice between their values and behavior - a key moment in building motivation.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4a": {"id": "node_4a", "persona_text": "Yeah. I never really thought about it that way, but you''re right. Every time I light up, she probably thinks about her dad.", "persona_mood": "neutral_uncertain", "themes": ["Relationships", "Change"], "choice_points": [{"id": "cp_node_4a_0", "option_text": "How does that realization sit with you?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect! This open question invites them to process this new awareness. After reflecting to build understanding, an open question helps them explore the implications.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4b": {"id": "node_4b", "persona_text": "Pretty terrible, actually. I don''t want to cause her pain. But I also feel trapped - like my own choices don''t matter.", "persona_mood": "neutral_uncertain", "themes": ["Autonomy", "Relationships", "Goals"], "choice_points": [{"id": "cp_node_4b_0", "option_text": "You''re caught between caring for her and feeling like you''ve lost your autonomy.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent double-sided reflection! You''ve named both sides of their internal conflict, which helps them hold the complexity of their situation.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4c": {"id": "node_4c", "persona_text": "It''s tense. She''s worried, I''m defensive. We end up in the same argument over and over. I smoke, she worries, I tell her I''m fine, she gets upset. Repeat.", "persona_mood": "neutral_uncertain", "themes": ["Resistance"], "choice_points": [{"id": "cp_node_4c_0", "option_text": "You''re both stuck in a painful cycle.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Good reflection! You''ve captured the stuck pattern. This opens the door for future exploration of what might break the cycle.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4d": {"id": "node_4d", "persona_text": "The hardest part is that I know she''s right. I know overspending is bad. I know it worries her. But I also feel like overspending is my choice, you know? I don''t like being told what to do.", "persona_mood": "neutral_uncertain", "themes": ["Health Concerns", "Autonomy", "Barriers"], "choice_points": [{"id": "cp_node_4d_0", "option_text": "Part of you agrees with her concerns, and part of you wants your choices to be respected.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect double-sided reflection! You''ve honored both their emerging awareness of the problem and their need for autonomy - both are valid and important.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4e": {"id": "node_4e", "persona_text": "Yeah. And guilty too, if I''m honest. I know it bothers her. I just don''t know what to do about it.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4e_0", "option_text": "What would need to be different for you to feel like you could make a change?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This open question explores what needs to shift. After reflecting their emotions, this invites problem-solving without prescribing solutions.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4f": {"id": "node_4f", "persona_text": "Exactly. I''m stuck. I care about her, but I don''t know if I''m strong enough to actually quit.", "persona_mood": "neutral_uncertain", "themes": ["Ambivalence", "Change"], "choice_points": [{"id": "cp_node_4f_0", "option_text": "What gives you any confidence at all that you might be able to do this?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This open question looks for strengths and resources, which builds self-efficacy. Even asking about ''any confidence at all'' honors their doubt while inviting them to identify positive resources.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4g": {"id": "node_4g", "persona_text": "I''ve tried before and failed. Twice. I''m not sure I have it in me to go through that again.", "persona_mood": "disappointed_closed", "themes": ["General"], "choice_points": [{"id": "cp_node_4g_0", "option_text": "You''ve tried before - twice - and those experiences left you doubting whether you can succeed.", "preview_hint": "MI-consistent approach", "rapport_impact": 1, "resistance_impact": -1, "tone_shift": 0.15, "technique_tags": ["simple_reflection"], "competency_links": ["B6"], "feedback": {"immediate": "Good reflection! You''ve captured both their effort (trying twice) and their current doubt. This validates their experience.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4h": {"id": "node_4h", "persona_text": "Yeah. I mean, I always knew it bothered her, but I kind of dismissed it as nagging. Seeing her actually scared... that''s different. Makes me wonder if I need to take this more seriously.", "persona_mood": "neutral_uncertain", "themes": ["Goals", "Change"], "choice_points": [{"id": "cp_node_4h_0", "option_text": "Something shifted when you saw her fear rather than just hearing complaints.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent! This reflection highlights a pivotal moment. You''re amplifying their own recognition that something has changed in how they see this.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_end_good", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4i": {"id": "node_4i", "persona_text": "Yeah, I guess I do.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_node_4i_0", "option_text": "Tell me about that guilt.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery! This open invitation encourages elaboration. After closed questions lead to brief responses, opening up with invitations helps restart exploration.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_4j": {"id": "node_4j", "persona_text": "Ideal? I guess I''d either quit completely, or she''d be okay with it. But I don''t think either is realistic. She''s never going to be okay with it, and quitting seems impossible.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_node_4j_0", "option_text": "You can imagine what you''d want - either you''d quit or she''d accept it - but both feel out of reach right now.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good complex reflection capturing their wishes and their sense of impossibility. This validates where they are while leaving space for future exploration.", "learning_note": "Reflections build rapport by showing you understand the customer''s perspective."}, "next_node_id": "node_end_moderate", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "node_end_good": {"id": "node_end_good", "persona_text": "You know, talking this through... I think I need to really think about what I want here. This conversation helped.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [], "is_endpoint": true, "endpoint_type": "neutral_end"}, "node_end_moderate": {"id": "node_end_moderate", "persona_text": "Thanks for listening. I need to think about all this.", "persona_mood": "neutral_uncertain", "themes": ["Goals"], "choice_points": [], "is_endpoint": true, "endpoint_type": "neutral_end"}, "node_end_stuck": {"id": "node_end_stuck", "persona_text": "Yeah. Look, I should get going. Thanks for your time.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "failed_engagement"}